class Solution {
    public boolean canChange(String start, String target) {
        int n = start.length();
        for (int i = 0; i < n; i++) {
            if (start.charAt(i) == 'L' && target.charAt(i) != '_' && target.charAt(i) != 'L') return false;
            if (start.charAt(i) == 'R' && target.charAt(i) != '_' && target.charAt(i) != 'R') return false;
            if (start.charAt(i) == '_' && target.charAt(i) == 'L' && i > 0 && start.charAt(i - 1) != 'L') return false;
            if (start.charAt(i) == '_' && target.charAt(i) == 'R' && i < n - 1 && start.charAt(i + 1) != 'R') return false;
        }
        return true;
    }
}
